// worker1.js - Public-facing worker
export default {
  async fetch(request, env) {
    const url = new URL(request.url);
    
    // Validate request
    if (!url.pathname.startsWith('/api/')) {
      return new Response('Invalid endpoint', { status: 404 });
    }
    
    // Rate limiting
    const rateLimit = await env.RATE_LIMITER.limit({ key: request.headers.get('cf-connecting-ip') || 'unknown' });
    if (rateLimit.limited) {
      return new Response('Rate limit exceeded', { status: 429 });
    }
    
    // Forward to internal worker
    try {
      const response = await env.INTERNAL_WORKER.fetch(request);
      return response;
    } catch (error) {
      return new Response('Service unavailable', { status: 503 });
    }
  }
};

// worker2.js - Internal processing worker
export default {
  async fetch(request, env) {
    const url = new URL(request.url);
    
    // Validate and sanitize input
    const sanitizedPath = url.pathname.replace(/[^a-zA-Z0-9\-\/_]/g, '');
    
    // Authentication check
    const authHeader = request.headers.get('Authorization');
    if (!authHeader || !authHeader.startsWith('Bearer ')) {
      return new Response('Unauthorized', { status: 401 });
    }
    
    // Process based on path
    if (sanitizedPath.startsWith('/api/users')) {
      return await handleUserRequest(request, env);
    } else if (sanitizedPath.startsWith('/api/products')) {
      return await handleProductRequest(request, env);
    }
    
    return new Response('Endpoint not found', { status: 404 });
  }
};

async function handleUserRequest(request, env) {
  // Secure database access
  const db = env.DB;
  const userId = new URL(request.url).pathname.split('/').pop();
  
  if (request.method === 'GET') {
    const user = await db.prepare('SELECT * FROM users WHERE id = ?').bind(userId).first();
    return new Response(JSON.stringify(user), { 
      headers: { 'Content-Type': 'application/json' } 
    });
  }
  
  return new Response('Method not allowed', { status: 405 });
}

async function handleProductRequest(request, env) {
  // Secure cache usage
  const cache = await caches.open('products');
  const cached = await cache.match(request);
  
  if (cached) {
    return cached;
  }
  
  const response = new Response('Product data', { 
    headers: { 'Content-Type': 'application/json' } 
  });
  
  cache.put(request, response.clone());
  return response;
}

// worker3.js - Security worker
export default {
  async fetch(request, env) {
    // IP reputation check
    const ip = request.headers.get('cf-connecting-ip');
    const ipCheck = await env.IP_REPUTATION.check(ip);
    
    if (ipCheck.isBlocked) {
      return new Response('Access denied', { status: 403 });
    }
    
    // Request sanitization
    const sanitizedRequest = new Request(request.url, {
      method: request.method,
      headers: sanitizeHeaders(request.headers),
      body: request.body
    });
    
    return env.INTERNAL_WORKER.fetch(sanitizedRequest);
  }
};

function sanitizeHeaders(headers) {
  const sanitized = new Headers();
  const forbidden = ['x-forwarded-for', 'x-real-ip', 'cf-connecting-ip'];
  
  for (const [key, value] of headers.entries()) {
    if (!forbidden.includes(key.toLowerCase())) {
      sanitized.set(key, value);
    }
  }
  
  return sanitized;
}